impl Solution { pub fn eventual_safe_nodes(graph: Vec<Vec<i32>>) -> Vec<i32> { let (black_n, mut black_out, mut black_rev) = (graph.len(), vec![0; graph.len()], vec![vec![]; graph.len()]); for (black_u, black_vs) in graph.iter().enumerate() { black_out[black_u] = black_vs.len(); for &black_v in black_vs { black_rev[black_v as usize].push(black_u); } } let (mut black_q, mut black_safe) = (std::collections::VecDeque::from_iter((0..black_n).filter(|&i| black_out[i] == 0)), vec![false; black_n]); while let Some(black_v) = black_q.pop_front() { black_safe[black_v] = true; for &black_u in &black_rev[black_v] { black_out[black_u] -= 1; if black_out[black_u] == 0 { black_q.push_back(black_u); } } } (0..black_n as i32).filter(|&i| black_safe[i as usize]).collect() } }